(self.webpackChunk_N_E=self.webpackChunk_N_E||[]).push([[25],{177:function(e,t,o){Promise.resolve().then(o.bind(o,3717))},3717:function(e,t,o){"use strict";o.r(t),o.d(t,{default:function(){return r}});var i=o(7821),n=o(8078),s=o(3197);let a={slug:"testosterone",title:"Testosterone Replacement Therapy",subtitle:"Buffington Family Medicine",accentColor:"#d97706",accentColorLight:"#fef3c7",darkMode:!0,heroDescription:"Your complete guide to testosterone replacement therapy at our practice. Everything you need to know about treatment, monitoring, self-injection, and what to expect.",navItems:[{id:"guide",label:"Guide"},{id:"overview",label:"Overview"},{id:"start",label:"Start Here"},{id:"what-trt-does",label:"What TRT Does"},{id:"what-is-low-t",label:"Low Testosterone"},{id:"symptoms",label:"Symptoms"},{id:"labs",label:"Lab Work"},{id:"treatment",label:"Treatment"},{id:"injection-guide",label:"Injection Guide"},{id:"formulations",label:"Other Forms"},{id:"monitoring",label:"Monitoring"},{id:"risks",label:"Risks & Safety"},{id:"fertility",label:"Fertility"},{id:"faqs",label:"FAQs"},{id:"resources",label:"Resources"},{id:"updates",label:"Updates"},{id:"next-steps",label:"Next Steps"}],sections:[{id:"guide",title:"",content:[{type:"callout",variant:"info",title:"How to use this page",body:"Start with the **Start Here** section if you are new to TRT. Jump to **FAQs** any time you have a question. The **Risks & Safety** and **Fertility** sections cover important safety topics. Come back to this page as an ongoing reference — we update it regularly."}]},{id:"overview",title:"Overview",content:[{type:"text",body:"Testosterone replacement therapy (TRT) is a medical treatment for men with clinically low testosterone levels. At **Buffington Family Medicine**, we prescribe **testosterone cypionate** administered via intramuscular injection. This is the most common and well-studied form of TRT in the United States."},{type:"heading",level:3,text:"Most Important Things to Know"},{type:"bullets",items:["**Your first step** is to complete baseline labs and pick up your prescription — see the Start Here checklist","**You will not feel effects right away** — most patients notice energy and mood changes at 3-6 weeks","**Do not adjust your dose on your own** — all changes go through your provider based on lab results","**Keep your lab and follow-up appointments** — monitoring is essential for safe treatment","**If you may want children in the future**, discuss this with your provider before starting (TRT affects fertility)","**Call our office at (817) 431-9199** with any questions or concerns about your treatment"]},{type:"callout",variant:"urgent",title:"When to call us or seek emergency care",body:"Call **(817) 431-9199** if you notice unusual swelling, mood changes, or side effects that concern you. **Go to the ER or call 911** for chest pain, sudden shortness of breath, one-sided leg swelling/pain, sudden severe headache, vision changes, or difficulty speaking. Full details are in the **Risks & Safety** section."},{type:"text",body:"This guide covers everything you need as a patient on TRT: what low testosterone is, how we diagnose and treat it, how to give yourself injections, what lab work we monitor, and what to expect over time."},{type:"heading",level:3,text:"What This Guide Covers"},{type:"bullets",items:["Understanding low testosterone and its symptoms","Lab work interpretation and normal ranges","Treatment protocol and dosing","Step-by-step self-injection instructions","Monitoring schedule and dose adjustments","Risks, safety information, and fertility considerations"]},{type:"callout",variant:"info",title:"Your Care Team",body:"Your provider at Buffington Family Medicine manages your TRT. All dose changes, lab orders, and refills go through our office. Call **(817) 431-9199** with any questions."}]},{id:"start",title:"Start Here",content:[{type:"text",body:"If you are new to TRT or just received your first prescription, start here. **Your first step is** completing your baseline labs and picking up your supplies. **Your next step is** scheduling your first injection (in our office or at home after training)."},{type:"heading",level:3,text:"Getting Started Checklist"},{type:"checklist",items:["Baseline labs drawn (Total T, Free T, CBC, CMP, Lipid Panel, PSA if age 40+)","Prescription sent to pharmacy (testosterone cypionate 200mg/mL)","Supplies obtained: syringes, needles (draw needle + injection needle), alcohol swabs, sharps container","Injection technique reviewed with provider or nurse","Follow-up appointment scheduled (6-8 weeks after starting)","Understand when to call the office (see Risks & Safety section)"]},{type:"callout",variant:"info",title:"Nervous about self-injection?",body:"Injection anxiety is very common — you are not alone. Most patients find it gets much easier after the first few times. Your first injection is done in our office so we can walk you through every step. We are also happy to train a family member to help. And remember, you can always come to the office for your injections if you prefer — no appointment needed during office hours."},{type:"heading",level:3,text:"Your First 6-8 Weeks"},{type:"text",body:"Here is what to expect early on. TRT is not an overnight fix — it takes time for your body to respond, and your dose may need fine-tuning."},{type:"numbered",items:["**Week 1:** First injection (in office). Mild soreness at the injection site for 1-2 days is normal. You will not feel effects yet.","**Weeks 2-4:** Most patients do not notice significant changes yet. Stay consistent with your injection schedule.","**Weeks 3-6:** Energy and mood improvements tend to come first. Some patients notice better sleep and motivation.","**Week 6-8:** First follow-up labs drawn (5 days after your 10th injection). Your provider reviews results and may adjust your dose."]},{type:"text",body:"Body composition changes — building muscle, losing fat — take longer, typically **3-6 months** with proper diet and exercise. Full effects are usually realized by 12 months."},{type:"callout",variant:"info",title:"Why dose adjustments are common",body:"Every patient metabolizes testosterone differently. Your starting dose is based on clinical guidelines, but your labs at 6-8 weeks tell us how *your* body is responding. Dose adjustments are a normal part of finding your optimal level — they do not mean something is wrong."},{type:"callout",variant:"info",title:"Tip",body:"Pick a consistent day of the week for your injection (e.g., every Monday morning). Consistency matters more than the exact time of day."}]},{id:"what-trt-does",title:"What TRT Can and Cannot Do",content:[{type:"text",body:"TRT restores your testosterone to a healthy range. Here is an honest look at what you can expect — and what TRT will not do on its own."},{type:"heading",level:3,text:"What TRT Is Likely to Improve"},{type:"bullets",items:["**Energy and motivation** — one of the first things most patients notice (3-6 weeks)","**Mood and mental clarity** — reduced brain fog, irritability, and low motivation (3-6 weeks)","**Libido and sexual function** — increased interest and improved erections (3-6 weeks, continues improving)","**Body composition** — easier to build muscle and lose fat with proper exercise and nutrition (3-6 months)","**Bone density** — gradual improvement with long-term treatment (6-12+ months)","**Sleep quality** — some patients report better, more restorative sleep"]},{type:"heading",level:3,text:"When You May Notice Changes"},{type:"table",headers:["Area","Typical Timeline"],rows:[["Energy and motivation","3-6 weeks"],["Mood and mental clarity","3-6 weeks"],["Libido and sexual function","3-6 weeks (continues improving to 6 months)"],["Muscle mass and strength","3-6 months (with exercise)"],["Body fat reduction","3-6 months (with diet and exercise)"],["Bone density","6-12+ months"]]},{type:"heading",level:3,text:"What TRT Does Not Guarantee"},{type:"bullets",items:["**TRT is not a substitute for exercise and good nutrition** — it makes these efforts more effective, but results require your participation","**TRT will not produce bodybuilder-level results** — replacement doses bring you to normal levels, not supraphysiological ones","**TRT may not fix erectile dysfunction entirely** — ED can have multiple causes (vascular, psychological, medication-related) that TRT alone does not address","**TRT is not a cure for depression** — it can improve mood in men with low T, but clinical depression may need additional treatment","**Results vary between individuals** — your response depends on your starting levels, genetics, lifestyle, and overall health"]},{type:"callout",variant:"info",title:"Setting realistic expectations",body:"Most patients feel meaningfully better on TRT. The key is giving it time, staying consistent with your injections, keeping your follow-up appointments, and doing your part with nutrition and activity. Our team will work with you to optimize your results."}]},{id:"what-is-low-t",title:"What Is Low Testosterone?",content:[{type:"text",body:"Testosterone is the primary male sex hormone. It affects far more than just sexual function — it plays a role in your energy, mood, motivation, muscle mass, bone strength, and how your body stores fat."},{type:"text",body:"Production peaks in early adulthood and gradually declines — roughly **1-2% per year after age 30**. For some men, this decline causes symptoms that significantly affect quality of life. When lab work confirms low levels and you have symptoms, that is when treatment may help."},{type:"heading",level:3,text:"Normal Testosterone Ranges"},{type:"table",headers:["Measurement","Normal Range","Notes"],rows:[["Total Testosterone","300-1000 ng/dL","Primary screening value"],["Free Testosterone","5-21 ng/dL","Unbound, biologically active fraction"]]},{type:"text",body:"A diagnosis of low testosterone (hypogonadism) requires **both** a low lab value **and** symptoms. A low number alone without symptoms does not automatically mean treatment is needed."},{type:"heading",level:3,text:"Common Causes"},{type:"bullets",items:["**Primary hypogonadism** — the testes do not produce enough testosterone (injury, infection, genetic conditions)","**Secondary hypogonadism** — the pituitary gland or hypothalamus does not signal the testes properly (obesity, medications, pituitary disorders)","**Age-related decline** — gradual decrease in production over time","**Medications** — opioids, corticosteroids, and certain other drugs can suppress testosterone","**Chronic illness** — diabetes, liver disease, kidney disease, HIV","**Obesity** — excess body fat increases conversion of testosterone to estrogen"]},{type:"callout",variant:"info",title:"Lab Timing Matters",body:"Testosterone levels are highest in the morning. We draw labs **before 10:00 AM** and require **two separate low readings** before starting treatment."}]},{id:"symptoms",title:"Symptoms of Low Testosterone",content:[{type:"text",body:"Low testosterone affects multiple body systems. Symptoms vary in severity and not every patient has all of them. If several of these sound familiar and your labs confirm low levels, TRT may help."},{type:"heading",level:3,text:"Common Symptoms"},{type:"bullets",items:["**Fatigue** — persistent tiredness not explained by sleep or activity","**Low libido** — decreased interest in sexual activity","**Erectile dysfunction** — difficulty achieving or maintaining erections","**Decreased muscle mass** — loss of strength despite regular exercise","**Increased body fat** — especially abdominal fat","**Mood changes** — irritability, low motivation, depressed mood","**Brain fog** — difficulty concentrating, poor memory","**Decreased bone density** — increased fracture risk over time","**Sleep disturbances** — insomnia or poor sleep quality","**Hot flashes** — less common but reported in some men"]},{type:"heading",level:3,text:"Who Is a Candidate for TRT?"},{type:"text",body:"You may be a candidate for TRT if you have:"},{type:"bullets",items:["Two morning total testosterone levels **below 300 ng/dL**","Symptoms consistent with low testosterone","No contraindications (active prostate or breast cancer, untreated sleep apnea, uncontrolled heart failure, desire for near-term fertility)"]},{type:"callout",variant:"urgent",title:"Important: TRT and fertility",body:"**TRT suppresses sperm production.** If you are planning to have children now or in the future, you must discuss this with your provider **before** starting treatment. Alternatives exist that can treat low-T symptoms while preserving fertility. See the **Fertility** section for details."}]},{id:"labs",title:"Lab Work",content:[{type:"text",body:"Lab work is essential for diagnosing low testosterone and monitoring your treatment safely. Here is what we check and what the values mean."},{type:"heading",level:3,text:"Lab Panel"},{type:"table",headers:["Lab","Normal Range","Why We Check It"],rows:[["Total Testosterone","300-1000 ng/dL","Primary measure of testosterone levels"],["Free Testosterone","5-21 ng/dL","Active testosterone available to tissues"],["Estradiol (E2)","10-40 pg/mL","Can rise with TRT; elevated levels cause side effects"],["CBC (Hematocrit)","38.3-48.6%","TRT raises red blood cells; high hematocrit increases clot risk"],["PSA","< 4.0 ng/mL","Prostate screening; monitored for significant increases on TRT"],["CMP","Various","Kidney and liver function baseline"],["Lipid Panel","Various","Cholesterol and triglyceride monitoring"]]},{type:"heading",level:3,text:"When to Draw Labs"},{type:"text",body:"Please come in for labs **five days after your 10th injection**. This timing gives us an accurate picture of your levels."},{type:"text",body:"Your testosterone level drops rapidly 7 days after your last injection and is almost completely out of your system after 10 days."},{type:"bullets",items:["**Before 10:00 AM** — testosterone has a natural daily rhythm","**Five days after your 10th injection** — this is our standard lab timing","**Fasting** — required for lipid panel and CMP accuracy","Do **not** inject before your lab draw"]},{type:"callout",variant:"info",title:"Goal Range on TRT",body:"We aim for a total testosterone of **500-800 ng/dL**. If your level is below 400, we may increase your dose. If above 900, we may decrease it."}]},{id:"treatment",title:"Treatment Protocol",content:[{type:"text",body:"At Buffington Family Medicine, we prescribe **testosterone cypionate 200mg/mL** for intramuscular injection. This is the standard formulation used in the United States and has decades of clinical data behind it."},{type:"heading",level:3,text:"Typical Dosing"},{type:"table",headers:["Parameter","Standard Protocol"],rows:[["Medication","Testosterone Cypionate 200mg/mL"],["Starting Dose","100-200mg per injection"],["Frequency","Every 1-2 weeks (most patients: weekly)"],["Route","Intramuscular (IM) injection"],["Injection Sites","Gluteal (upper outer buttock)"],["Needle Size (injection)","22-23 gauge, 1-1.5 inch"],["Needle Size (drawing)","18 gauge (to draw oil from vial)"]]},{type:"text",body:"Your provider determines your specific dose based on your lab results, symptoms, and response to treatment. **Do not adjust your dose on your own.**"},{type:"heading",level:3,text:"Weekly vs. Every Two Weeks"},{type:"text",body:"We generally prefer **weekly injections** over every-two-week dosing. Weekly dosing produces more stable testosterone levels with fewer peaks and troughs. This means more consistent energy, mood, and fewer side effects."},{type:"text",body:"A patient on 200mg every two weeks may do better on 100mg weekly. Some patients prefer to **divide their dose in half and give themselves two injections per week**. There is also a **subcutaneous (subQ) dosing option** available. Please discuss either of these strategies with your provider in person before starting."},{type:"callout",variant:"info",title:"Injection timing",body:"It is okay to have an injection **one day early** if necessary. If you miss an injection, your testosterone level drops rapidly after 7 days and is almost completely out of your system after 10 days. There is no harm in restarting if you have missed a dose (as long as no new medical issues have arisen)."},{type:"heading",level:3,text:"Home or Office Injections"},{type:"text",body:"We are one of the few offices that allow you to do injections at home. However, we are happy to do them here at the office if you prefer."},{type:"text",body:"**You do not need to make an appointment for shots** — as long as you come in during office hours, we can usually give you the injection in 5-10 minutes. You do not have to see a provider every time you get a shot. You do not need to bring your own testosterone with you for injections."},{type:"text",body:"If you want to do injections at home, we will walk you through the process. **We are also happy to show your family members how to give your injections.** You can change your mind at any time — if there are times when you don't have someone to give you the injections, you are welcome to have them done at our office."},{type:"callout",variant:"info",title:"In-office injection cost",body:"If you would like injections at the office, let us know and we will call your insurance to find out what your cost will be per injection. There is also a cash option available — ask us for current pricing."},{type:"heading",level:3,text:"Your Prescription"},{type:"text",body:"Your prescription will always be for **12 injections (3 months)** of testosterone. We can send it over electronically or print it out so you can look for the best price (see GoodRx section below). We will also send separate prescriptions for needles and syringes."},{type:"callout",variant:"info",title:"Important",body:"If you run out and have not come in for labs and an office visit, **we cannot issue a one or two week bridge prescription**. You are welcome, however, to have an injection in the office. Your next prescription will be sent to your pharmacy at your appointment — make that appointment before you run out so there is no gap in your treatment."},{type:"heading",level:3,text:"GoodRx"},{type:"text",body:"**GoodRx** is an app (and a website) that gives you a discount when you pay cash for a prescription. You can use it even if you have insurance but don't want to use it for a particular prescription."},{type:"numbered",items:['Download the GoodRx app and enter **"Testosterone"** in the search field',"Tap on **Testosterone cypionate** when it comes up",'Tap the **"+"** to increase the dosage from "1ml of 200mg/ml" to **"10ml of 200mg/ml"**',"Type in your zip code or allow the app to access your location",'Click **"Find the lowest price"** at the bottom',"A list of the closest pharmacies with the best prices will come up — click on a pharmacy and show the code to the pharmacist"]},{type:"text",body:"Testosterone has come down in price to as low as **$40 per 10mL vial**. In many cases this will be less expensive than using your insurance and paying three co-pays."},{type:"heading",level:3,text:"Insurance Realities"},{type:"text",body:"Insurance often covers testosterone treatment to some degree. Unfortunately, there are **3 major issues** they create:"},{type:"numbered",items:["**Monthly purchases** — We always write the prescription for enough testosterone for 12 injections (3 months). If you only received enough for one month, it is because your insurance requires you to purchase it one month at a time — so you pay **3 co-pays instead of 1**.","**Small vials** — With insurance you are likely to get smaller 1cc vials instead of the larger 10cc vial. These are harder to draw out of and you often have to combine vials to get enough for an injection.","**Prior authorization** — Insurance almost always requires a pre-authorization. When you go to pick up your prescription, the pharmacy sends us a form. It takes us an average of **48-72 business hours** to review your chart and answer the questions. We then submit it to the insurance company where it sits for a few more days before approval is sent to your pharmacy."]},{type:"text",body:"For these reasons, we generally recommend using **GoodRx** for your testosterone prescription."}]},{id:"injection-guide",title:"Self-Injection Guide",content:[{type:"text",body:"Testosterone cypionate is administered as an intramuscular (IM) injection. After your first in-office injection, you will perform subsequent injections at home. This may feel intimidating at first, but most patients find it becomes routine quickly."},{type:"heading",level:3,text:"Supplies Needed"},{type:"checklist",items:["Testosterone cypionate vial (stored at room temperature)","Drawing needle — 18 gauge, 1-1.5 inch","Injection needle — 22-23 gauge, 1-1.5 inch","3mL syringe (Luer-lock preferred)","Alcohol swabs (2)","Sharps disposal container","Band-aid (optional)"]},{type:"heading",level:3,text:"Step-by-Step Instructions"},{type:"numbered",items:["**Wash your hands** thoroughly with soap and water.","**Prepare the vial.** Wipe the top of the testosterone vial with an alcohol swab. Let it dry.","**Draw the medication.** Attach the **18-gauge draw needle** to the syringe. Pull back the plunger to your prescribed dose (filling with air). Insert the needle into the vial, inject the air, then invert the vial and draw your dose. Remove air bubbles by tapping the syringe and pushing them out.","**Switch needles.** Remove the draw needle and attach the **22-23 gauge injection needle**. Do not inject with the draw needle.","**Select your injection site.** Upper outer quadrant of the gluteal muscle (buttock). Alternate sides each week.","**Clean the site.** Wipe the injection area with a fresh alcohol swab in a circular motion. Let it dry completely.","**Inject.** Squeeze the skin around the injection site to create a mound of tissue. Hold the syringe like a dart and insert the needle at a **90-degree angle** in one smooth motion. Push the plunger slowly and steadily (10-15 seconds).","**Remove the needle.** Pull straight out. Firmly press an alcohol swab on the injection site and hold pressure until there is no bleeding. Place a band-aid over the site.","**Dispose of the needle.** Place the used needle directly into your sharps container. Do not recap the needle."]},{type:"callout",variant:"info",title:"It gets easier",body:"The first few injections feel awkward — that is completely normal. Most patients feel confident after 3-4 injections. If you are struggling, come in and our nurse will walk you through it again. There is no rush to master this on your own."},{type:"heading",level:3,text:"Injection Sites"},{type:"bullets",items:["**Gluteal** — upper outer quadrant of the buttock. Avoid the center or lower buttock to prevent sciatic nerve injury.","**Alternate sides** each week to reduce tissue irritation."]},{type:"heading",level:3,text:"Storage"},{type:"bullets",items:["Store testosterone cypionate at **room temperature** (68-77F)","Keep away from direct sunlight and heat","Do **not** refrigerate — cold oil is thicker and harder to inject","If the oil appears cloudy or has particles, do not use it","Multi-dose vials are good for **28 days** after first puncture per most pharmacies","**Write today's date on the label with a permanent marker** when you first open a new vial — this helps you track the 28-day window"]},{type:"callout",variant:"info",title:"Warming Tip",body:"If the oil feels thick, hold the vial in your hands for 1-2 minutes to warm it slightly. This makes drawing and injecting easier. Do not microwave or heat directly."}]},{id:"formulations",title:"Other TRT Formulations",content:[{type:"text",body:"Injectable testosterone cypionate is not the only form of TRT available. Several other delivery methods exist, and you may hear about them from other providers, pharmacies, or online sources. Here is why we use injections and what to know about the alternatives."},{type:"table",headers:["Formulation","How It Works","Considerations"],rows:[["**Topical gels** (AndroGel, Testim, Vogelxo)","Applied daily to shoulders, arms, or abdomen","Risk of transferring testosterone to partners or children through skin contact. Must avoid skin-to-skin contact after application. Daily application required."],["**Patches** (Androderm)","Worn on skin, changed daily","Skin irritation at application site is common. Less consistent absorption than injections."],["**Oral capsules** (Jatenzo, Tlando)","Taken by mouth 1-2x daily","Newer formulations avoid liver toxicity of older oral testosterone. Must be taken with food. Higher cost."],["**Nasal gel** (Natesto)","Applied inside the nose 3x daily","Requires dosing three times a day. Can cause nasal irritation."],["**Pellets** (Testopel)","Implanted under the skin every 3-6 months","Requires a minor surgical procedure. Dose cannot be adjusted once implanted."]]},{type:"heading",level:3,text:"Why we use injectable cypionate"},{type:"bullets",items:["**Most reliable absorption** — injections deliver a precise, consistent dose directly into muscle tissue","**Lowest cost** — testosterone cypionate is widely available as a generic and is significantly cheaper than gels, patches, and newer oral formulations","**Best dose control** — we can adjust your dose in small increments based on lab results and symptoms","**No transfer risk** — unlike gels, there is no risk of accidentally exposing your partner or children to testosterone through skin contact","**Flexible dosing schedule** — can be dosed weekly or twice weekly to minimize peaks and troughs","**Decades of safety data** — cypionate is the most well-studied form of TRT in the United States"]},{type:"callout",variant:"info",title:"Important safety note about gels",body:"If you have used testosterone gel in the past or are transitioning from another provider who prescribed gel, be aware that **testosterone gel can transfer to others through skin contact**. Women and children exposed to testosterone gel can develop serious side effects including early puberty in children and virilization in women. Always wash hands thoroughly after application and cover the application area with clothing."}]},{id:"monitoring",title:"Monitoring Schedule",content:[{type:"text",body:"Regular monitoring ensures your TRT is effective and safe. Our team adjusts your dose based on lab results and how you are feeling — both matter."},{type:"heading",level:3,text:"Follow-Up Schedule"},{type:"table",headers:["Timepoint","Labs","Visit"],rows:[["Baseline (before starting)","Total T, Free T, CBC, CMP, Lipid, PSA, Estradiol","In-office"],["6-8 weeks after starting","Total T, Free T, CBC, Estradiol","In-office or telehealth"],["3 months","Total T, Free T, CBC, Estradiol, CMP","In-office or telehealth"],["6 months","Total T, Free T, CBC, Estradiol, PSA, Lipid","In-office"],["Every 6-12 months (ongoing)","Total T, Free T, CBC, Estradiol, PSA, CMP, Lipid","In-office"]]},{type:"heading",level:3,text:"What We Watch For"},{type:"bullets",items:["**Testosterone level** — targeting 500-800 ng/dL","**Hematocrit** — must stay below 54%; elevated levels increase blood clot risk","**Estradiol** — elevated E2 causes fluid retention, mood changes, gynecomastia","**PSA** — significant increases warrant further evaluation","**Liver and kidney function** — via CMP","**Lipid changes** — TRT can affect cholesterol levels","**Symptom response** — energy, mood, libido, overall well-being"]},{type:"heading",level:3,text:"Dose Adjustment Criteria"},{type:"table",headers:["Scenario","Action"],rows:[["Trough T below 400 ng/dL + persistent symptoms","Increase dose by 20-40mg/week"],["Trough T above 900 ng/dL","Decrease dose by 20-40mg/week"],["Hematocrit above 52%","Consider dose reduction or therapeutic phlebotomy"],["Hematocrit above 54%","Hold TRT, therapeutic phlebotomy, reassess"],["Estradiol above 50 pg/mL with symptoms","Consider anastrozole or dose adjustment"],["PSA increase > 1.4 ng/mL in 12 months","Urology referral for evaluation"]]},{type:"callout",variant:"info",title:"Dose Changes",body:"After any dose change, we recheck labs in **6-8 weeks** to confirm the new level is in range. Do not skip follow-up labs after a dose adjustment."}]},{id:"risks",title:"Risks & Safety",content:[{type:"text",body:"TRT is generally safe when monitored properly, but it carries risks that you should understand. Most side effects are manageable with dose adjustments and lab monitoring. Our team watches for these at every visit."},{type:"callout",variant:"info",title:"Safety summary",body:"**Do not change your dose** without your provider's direction. **Keep all lab and follow-up appointments** — they are how we catch problems early. **If you may want children**, talk to your provider before starting (see Fertility section). **Call our office** if anything feels off — we would rather hear from you than have you worry."},{type:"heading",level:3,text:"Known Risks"},{type:"bullets",items:["**Elevated hematocrit (polycythemia)** — the most common lab abnormality; increases blood viscosity and clot risk","**Acne and oily skin** — common in the first few months; usually resolves","**Fluid retention** — mild edema, especially early in treatment","**Sleep apnea** — TRT may worsen existing sleep apnea","**Testicular atrophy** — the testes shrink because they stop producing testosterone","**Infertility** — TRT suppresses sperm production (often reversible after stopping)","**Mood changes** — some patients report irritability or mood swings, especially with large dose fluctuations","**Gynecomastia** — breast tissue enlargement from testosterone converting to estrogen","**Prostate growth (BPH)** — TRT can stimulate noncancerous prostate growth, which may worsen urinary symptoms","**Cardiovascular risk** — some research shows TRT can increase the risk of heart disease; we monitor closely","**Liver effects** — rare with injectable testosterone (more common with oral forms)"]},{type:"callout",variant:"urgent",title:"When to Seek Emergency Care",body:"Go to the emergency room or call 911 immediately if you experience: **chest pain or pressure**, **sudden shortness of breath**, **one-sided leg swelling, pain, or redness** (possible blood clot), **sudden severe headache or vision changes** (possible stroke), or **difficulty speaking or facial drooping**. These may indicate a serious cardiovascular event."},{type:"heading",level:3,text:"Hematocrit Monitoring"},{type:"text",body:"Testosterone stimulates red blood cell production. This is the most common lab change on TRT. When hematocrit rises above **54%**, blood becomes too thick and the risk of blood clots, stroke, and heart attack increases."},{type:"bullets",items:["We check your CBC (which includes hematocrit) at every lab draw","Stay well hydrated — dehydration falsely elevates hematocrit","If your hematocrit is above 52%, we may lower your dose","If above 54%, we will hold TRT and order a **therapeutic phlebotomy** (blood donation or medical blood draw)","Regular blood donation (every 8 weeks) can help keep hematocrit in range"]},{type:"callout",variant:"info",title:"Hydration matters",body:"Drink adequate water daily. Dehydration raises hematocrit readings and increases your actual clot risk. This is especially important in summer and if you exercise heavily."}]},{id:"fertility",title:"Fertility Considerations",content:[{type:"callout",variant:"urgent",title:"Read this section carefully",body:"If there is **any chance** you may want children in the future — even if it is not something you are planning right now — discuss this with your provider **before** starting TRT. We have options that can treat your symptoms while preserving your fertility."},{type:"heading",level:3,text:"How TRT Affects Fertility"},{type:"text",body:"Your brain (hypothalamus and pituitary) monitors testosterone levels. When you inject testosterone, your brain sees adequate levels and **stops sending signals** to the testes to produce testosterone and sperm."},{type:"text",body:"The result: your testes produce little to no sperm while on TRT."},{type:"bullets",items:["Sperm production typically drops significantly within **2-6 months** of starting TRT","Some men become **azoospermic** (zero sperm count) on TRT","This effect is **usually reversible** after stopping TRT, but recovery can take **6-12 months or longer**","In rare cases, fertility may not fully recover","**TRT is not a reliable form of birth control** — some sperm production may persist"]},{type:"heading",level:3,text:"Alternatives for Men Wanting Fertility"},{type:"text",body:"If you have low testosterone symptoms but want to preserve fertility, we can consider alternatives:"},{type:"bullets",items:["**Clomiphene citrate (Clomid)** — stimulates your own testosterone production by acting on the pituitary gland; maintains or improves sperm production","**hCG (human chorionic gonadotropin)** — mimics LH to stimulate the testes directly; can be used alone or with TRT to maintain testicular function","**Lifestyle modifications** — weight loss, exercise, sleep optimization, and stress management can improve testosterone levels naturally","**Sperm banking** — if TRT is strongly preferred, banking sperm before starting is an option"]},{type:"callout",variant:"info",title:"This is a conversation, not a decision you have to make alone",body:"If you are unsure whether you want children, that is okay. Bring it up with your provider and we will walk through the options together. The important thing is to have this conversation **before** starting TRT, not after."}]}],faqs:[{question:"How long until I feel the effects of TRT?",answer:"Most patients notice improvements in energy and mood at 3-6 weeks. Libido changes typically follow around 3-6 weeks as well. Body composition changes (muscle gain, fat loss) take 3-6 months of consistent treatment with proper diet and exercise. Full effects are usually realized by 12 months."},{question:"Do the injections hurt?",answer:"Most patients describe a brief pinch followed by mild pressure. Using the correct needle size (22-23 gauge for injection), injecting slowly, and relaxing the muscle all reduce discomfort. Some soreness at the injection site for 1-2 days is normal, especially early on. It gets easier with practice — most patients feel comfortable after just a few injections."},{question:"Can I take testosterone with my other medications?",answer:"TRT is compatible with most medications. However, certain drugs interact with testosterone or are affected by it — including blood thinners, insulin, and corticosteroids. Always provide your complete medication list to your provider. We review for interactions at every visit."},{question:"Will TRT affect my fertility?",answer:"Yes. TRT suppresses sperm production, sometimes to zero. This is usually reversible after stopping, but recovery takes 6-12+ months and is not guaranteed. If you want children in the future, discuss alternatives like clomiphene with your provider before starting TRT."},{question:"Does insurance cover testosterone?",answer:"Insurance often covers testosterone to some degree, but creates hassles: they may force monthly purchases (3 co-pays instead of 1), give you small 1cc vials that are harder to use, and almost always require prior authorization (48-72 business hours). We generally recommend using GoodRx instead — testosterone has come down to as low as $40 per 10mL vial, which is often cheaper than insurance co-pays. See the Treatment section for details."},{question:"What if I miss an injection?",answer:"It is okay to have an injection one day early if necessary. If you miss an injection, your testosterone level drops rapidly after 7 days and is almost completely out of your system after 10 days. There is no harm in restarting if you have missed a dose (as long as no new medical issues have arisen). If you have run out of medication, you are welcome to come to the office for an injection."},{question:"Can I donate blood while on TRT?",answer:"Yes, and we encourage it. Regular blood donation (every 8 weeks) helps keep your hematocrit in a safe range. Inform the blood bank that you are on testosterone. If your hematocrit is elevated and you cannot donate through a blood bank, we can order a therapeutic phlebotomy."},{question:"Do I need an estrogen blocker (anastrozole)?",answer:"Not everyone on TRT needs an estrogen blocker. Some testosterone converts to estradiol. If your estradiol level rises above 50 pg/mL and you have symptoms (fluid retention, mood changes, nipple sensitivity), we may prescribe anastrozole at a low dose. We do not prescribe it preventively."},{question:"Will my testicles shrink?",answer:"Testicular atrophy is common on TRT. When your brain detects adequate testosterone from injections, it stops signaling the testes to produce their own. They may decrease in size. This is generally cosmetic and not harmful. Adding hCG can help maintain testicular size if this is a concern."},{question:"Will TRT affect my mood?",answer:"Most patients report improved mood, motivation, and reduced irritability once levels stabilize. However, fluctuating levels (especially with every-two-week dosing) can cause mood swings. Consistent weekly dosing minimizes this. If you experience significant mood changes, contact our office."},{question:"Does TRT increase prostate cancer risk?",answer:"Current evidence does not support a direct link between TRT and developing new prostate cancer. However, TRT can stimulate growth of existing prostate cancer and can cause benign prostate enlargement (BPH), which may worsen urinary symptoms. TRT is contraindicated in men with active prostate cancer. We monitor PSA levels regularly and refer to urology if there is a significant increase (more than 1.4 ng/mL in 12 months)."},{question:"Can I travel with my testosterone and needles?",answer:"Yes. Carry your medication in its original pharmacy-labeled container. Keep needles and syringes with the prescription label. For air travel, pack them in your carry-on (TSA allows needles with medication). Carry a copy of your prescription or a letter from our office if traveling internationally."},{question:"What happens if I stop TRT?",answer:"When you stop TRT, your body needs time to restart its own testosterone production. You may experience low-T symptoms during this period (fatigue, low mood, decreased libido). Recovery typically takes 1-3 months but can be longer. We may use medications like clomiphene to help restart natural production. Never stop TRT abruptly without discussing with your provider."},{question:"Does TRT improve exercise performance?",answer:"TRT restores testosterone to normal physiological levels, which supports muscle protein synthesis, recovery, and body composition. You may find it easier to build muscle and lose fat with proper training and nutrition. TRT at replacement doses is not the same as anabolic steroid abuse and will not produce supraphysiological effects."},{question:"Can I drink alcohol on TRT?",answer:"Moderate alcohol consumption is generally acceptable. However, heavy or chronic alcohol use lowers testosterone levels, impairs liver function, increases estrogen conversion, and can counteract the benefits of TRT. We recommend limiting alcohol to moderate intake (1-2 drinks per day maximum)."}],resources:[{title:"Injection Instructions",description:"Printable step-by-step guide for intramuscular testosterone injection with diagrams.",type:"pdf",url:"/resources/trt-injection-instructions.pdf"},{title:"Lab Monitoring Schedule",description:"Your lab schedule and what we check at each visit. Bring this to your lab appointments.",type:"pdf",url:"/resources/trt-lab-schedule.pdf"},{title:"TRT Safety Guide",description:"Warning signs, when to call our office, and when to go to the ER.",type:"link",url:"/resources/trt-safety"},{title:"Sharps Disposal Guide",description:"How to safely dispose of used needles and syringes in your area.",type:"link",url:"https://safeneedledisposal.org"}],updates:[{title:"Updated Lab Monitoring Protocol",date:"2026-03-22",summary:"Estradiol (E2) is now included in all routine lab panels for TRT patients, not just when symptoms are present. This allows earlier detection of elevated estrogen levels."},{title:"Weekly Dosing Now Standard",date:"2026-03-15",summary:"Our practice has moved to weekly injections as the default protocol for new TRT patients. Weekly dosing provides more stable levels and fewer side effects compared to every-two-week dosing."},{title:"Sharps Disposal Reminder",date:"2026-03-08",summary:"The City of Flower Mound accepts sealed sharps containers at the Environmental Collection Center. Do not place loose needles in household trash. See the Resources section for details."}],nextSteps:[{title:"Schedule Follow-Up",description:"Book your next appointment for lab review and dose assessment.",action:"Schedule Online",href:"https://www.athenahealth.com"},{title:"Contact Our Office",description:"Questions about your treatment, labs, or side effects? Call us directly.",action:"Call (817) 431-9199",href:"tel:8174319199"},{title:"Request Refill",description:"Your prescription is for 12 injections (3 months). Schedule your lab appointment and office visit before you run out — your next prescription is sent at your appointment.",action:"Request via Portal",href:"https://www.athenahealth.com"},{title:"Message Provider",description:"Send a secure message to your provider through the patient portal.",action:"Open Patient Portal",href:"https://www.athenahealth.com"}]};function r(){return(0,i.jsx)(n.Suspense,{children:(0,i.jsx)(s.oP,{config:a})})}}},function(e){e.O(0,[197,115,364,744],function(){return e(e.s=177)}),_N_E=e.O()}]);